+    #[test]
+    fn failed_respects_max_retries() {
+        let policy = RetryPolicy {
+            max_retries: 2,
+            ..Default::default()
+        };
+        // Attempt 3 (exceeds max_retries=2)
+        let decision = plan_recovery(Action::Pause, ActionFailure::Failed, 3, &policy);
+        assert_eq!(decision.kind, FailureKind::Permanent);
+    }
